/*
  Global Design System
  Matches straightforward, industrial Google Sites-style layout
*/

:root {
    /* Color Palette */
    --color-primary-900: #212121; /* Dark text / header divider */
    --color-primary-000: #FFFFFF; /* White */

    --color-secondary-300: #BDBDBD; /* Borders, divider bar */
    --color-secondary-050: #F1F1F1; /* Light gray backgrounds */

    --color-neutral-900: #212121;
    --color-neutral-700: #424242;
    --color-neutral-500: #9E9E9E;
    --color-neutral-050: #F1F1F1;
    --color-neutral-000: #FFFFFF;

    --color-accent: #00C853; /* Active nav link */

    --color-success: #00C853;
    --color-error: #D32F2F;
    --color-warning: #FFA000;
    --color-info: #1976D2;

    /* Typography */
    --font-heading: "Space Grotesk", Helvetica, sans-serif;
    --font-body: "Source Sans 3", Arial, sans-serif;
    --font-code: "Source Code Pro", monospace;

    --font-size-h1: 56px;
    --font-size-h2: 32px;
    --font-size-h3: 24px;
    --font-size-body: 16px;
    --font-size-small: 14px;

    --font-weight-light: 300;
    --font-weight-regular: 400;
    --font-weight-medium: 500;
    --font-weight-semibold: 600;
    --font-weight-bold: 700;

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.75;

    /* Spacing scale (8px base) */
    --space-0-5: 4px;
    --space-1: 8px;
    --space-2: 16px;
    --space-3: 24px;
    --space-4: 32px;
    --space-5: 48px;
    --space-6: 64px;

    /* Layout */
    --layout-max-width: 1200px;
    --sidebar-width: 220px;
}

/* Reset & Base Styles */

*, *::before, *::after {
    box-sizing: border-box;
}

html,
body {
    margin: 0;
    padding: 0;
}

body {
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-900);
    background-color: var(--color-neutral-050);
}

a {
    color: inherit;
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

/* Header & Hero */

.site-header {
    width: 100%;
}

.hero {
    position: relative;
    width: 100%;
    min-height: 320px;
    max-height: 420px;
    background-image: url("hero-metal-fabrication.jpg"); /* Replace with real path */
    background-size: cover;
    background-position: center center;
    background-repeat: no-repeat;
}

.hero-overlay {
    position: relative;
    width: 100%;
    height: 100%;
    background: linear-gradient(
        to bottom,
        rgba(0, 0, 0, 0.55),
        rgba(0, 0, 0, 0.55)
    );
    color: var(--color-primary-000);
}

.hero-inner {
    max-width: var(--layout-max-width);
    margin: 0 auto;
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
    padding-left: var(--space-2);
    padding-right: var(--space-2);
    text-align: center;
}

.hero-title-block {
    margin-bottom: var(--space-4);
}

.site-title {
    margin: 0;
    font-family: var(--font-heading);
    font-size: var(--font-size-h1);
    font-weight: var(--font-weight-bold);
    line-height: var(--line-height-tight);
}

.site-subtitle {
    margin-top: var(--space-1);
    margin-bottom: 0;
    font-size: var(--font-size-body);
    font-weight: var(--font-weight-regular);
}

.hero-nav {
    margin-top: var(--space-3);
}

.hero-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: inline-flex;
    gap: var(--space-4);
}

.hero-nav-item {
    font-size: var(--font-size-body);
}

.hero-nav-link {
    color: var(--color-primary-000);
    font-weight: var(--font-weight-medium);
}

.hero-nav-link.is-active {
    color: var(--color-accent);
}

.hero-nav-link:hover,
.hero-nav-link:focus {
    text-decoration: underline;
}

/* Gray divider bar under hero */

.header-divider {
    width: 100%;
    height: 8px;
    background-color: var(--color-secondary-300);
}

/* Main Layout */

.site-main {
    width: 100%;
}

.site-body {
    max-width: var(--layout-max-width);
    margin: 0 auto;
    background-color: var(--color-neutral-000);
    display: flex;
    align-items: stretch;
    min-height: 320px;
}

/* Sidebar navigation */

.sidebar {
    flex: 0 0 var(--sidebar-width);
    background-color: var(--color-secondary-050);
    border-right: 1px solid var(--color-secondary-300);
    padding-top: var(--space-4);
    padding-bottom: var(--space-4);
    padding-left: var(--space-2);
    padding-right: var(--space-2);
}

.sidebar-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
}

.sidebar-nav-item + .sidebar-nav-item {
    margin-top: var(--space-2);
}

.sidebar-nav-link {
    display: block;
    font-size: var(--font-size-body);
    font-weight: var(--font-weight-regular);
    color: var(--color-neutral-900);
}

.sidebar-nav-link.is-active {
    font-weight: var(--font-weight-semibold);
}

.sidebar-nav-link:hover,
.sidebar-nav-link:focus {
    text-decoration: underline;
}

/* Page content area */

.page-content {
    flex: 1 1 auto;
    padding-top: var(--space-4);
    padding-bottom: var(--space-5);
    padding-left: var(--space-4);
    padding-right: var(--space-4);
}

.page-content h1,
.page-content h2,
.page-content h3 {
    font-family: var(--font-heading);
    color: var(--color-neutral-700);
    margin-top: 0;
}

.page-content h1 {
    font-size: var(--font-size-h2);
    font-weight: var(--font-weight-semibold);
    line-height: var(--line-height-tight);
    margin-bottom: var(--space-2);
}

.page-content h2 {
    font-size: var(--font-size-h3);
    font-weight: var(--font-weight-semibold);
    margin-bottom: var(--space-2);
}

.page-content p {
    margin-top: 0;
    margin-bottom: var(--space-2);
    color: var(--color-neutral-900);
}

/* Footer */

.site-footer {
    margin-top: var(--space-4);
    background-color: var(--color-secondary-050);
    border-top: 1px solid var(--color-secondary-300);
    color: var(--color-neutral-700);
}

.footer-inner {
    max-width: var(--layout-max-width);
    margin: 0 auto;
    padding-top: var(--space-3);
    padding-bottom: var(--space-3);
    padding-left: var(--space-2);
    padding-right: var(--space-2);
    text-align: center;
}

.footer-nav-list {
    list-style: none;
    margin: 0 0 var(--space-2) 0;
    padding: 0;
    display: inline-flex;
    flex-wrap: wrap;
    justify-content: center;
    gap: var(--space-2);
}

.footer-nav-link {
    font-size: var(--font-size-small);
    color: var(--color-neutral-700);
}

.footer-nav-link:hover,
.footer-nav-link:focus {
    text-decoration: underline;
}

.footer-meta {
    margin: 0;
    font-size: var(--font-size-small);
    color: var(--color-neutral-500);
}

/* Responsive adjustments */

@media (max-width: 960px) {
    .hero-inner {
        padding-top: var(--space-4);
        padding-bottom: var(--space-4);
    }

    .site-title {
        font-size: 40px;
    }

    .hero-nav-list {
        gap: var(--space-2);
    }

    .site-body {
        flex-direction: column;
    }

    .sidebar {
        flex: 0 0 auto;
        width: 100%;
        border-right: none;
        border-bottom: 1px solid var(--color-secondary-300);
        display: flex;
        justify-content: center;
    }

    .sidebar-nav-list {
        display: flex;
        flex-wrap: wrap;
        justify-content: center;
        column-gap: var(--space-3);
        row-gap: var(--space-1);
    }

    .sidebar-nav-item + .sidebar-nav-item {
        margin-top: 0;
    }

    .page-content {
        padding-left: var(--space-2);
        padding-right: var(--space-2);
    }
}

@media (max-width: 600px) {
    .hero {
        min-height: 260px;
    }

    .site-title {
        font-size: 32px;
    }

    .hero-nav-list {
        flex-direction: column;
        gap: var(--space-1);
    }
}
